--- a/App/Layers/W1/BaseApp/Projects/Project/Job/CopyJob.Codeunit.al
+++ b/App/Layers/W1/BaseApp/Projects/Project/Job/CopyJob.Codeunit.al
@@ -192,6 +192,8 @@
                     TargetJobPlanningLine."Completely Picked" := false;
                     TargetJobPlanningLine."Ledger Entry No." := 0;
                     TargetJobPlanningLine."Ledger Entry Type" := TargetJobPlanningLine."Ledger Entry Type"::" ";
+                    if TargetJobPlanningLine.Type = TargetJobPlanningLine.Type::Item then
+                        TargetJobPlanningLine."System-Created Entry" := false;
                     OnCopyJobPlanningLinesOnBeforeTargetJobPlanningLineInsert(TargetJobPlanningLine, SourceJobPlanningLine);
                     TargetJobPlanningLine.Insert(true);
                     OnCopyJobPlanningLinesOnAfterTargetJobPlanningLineInsert(TargetJobPlanningLine, SourceJobPlanningLine);

test_patch:
diff --git a/App/Layers/W1/Tests/Job/JobInvoicing.Codeunit.al b/App/Layers/W1/Tests/Job/JobInvoicing.Codeunit.al
--- a/App/Layers/W1/Tests/Job/JobInvoicing.Codeunit.al
+++ b/App/Layers/W1/Tests/Job/JobInvoicing.Codeunit.al
@@ -58,6 +58,7 @@
         DetailLevel: Option All,"Per Job","Per Job Task","Per Job Planning Line";
         LineDiscountPctErr: Label '%1 should be %2', Comment = '%1 = Field Caption, %2 = Field Value';
         WrongNoOfLinesLbl: Label 'Wrong number of lines created.';
+        ValueNotTrueErr: Label 'Value must be equal to true';

     [Test]
     [HandlerFunctions('TransferToInvoiceHandler,MessageHandler')]
@@ -4041,6 +4042,44 @@


         Assert.AreEqual(1, InvoicesList.Count, WrongNoOfLinesLbl);
+    end;
+
+    [Test]
+    [HandlerFunctions('MessageHandler,ConfirmHandler')]
+    [Scope('OnPrem')]
+    procedure CopyJobAndCreateProjectJournalLineWithoutError()
+    var
+        Job: Record Job;
+        JobPlanningLine: Record "Job Planning Line";
+        JobTask: Record "Job Task";
+        JobJournalLine: Record "Job Journal Line";
+        CopyJob: Codeunit "Copy Job";
+        JobLineType: Enum "Job Line Type";
+        TargetJobNo: Code[20];
+    begin
+        // [SCENARIO 573397] Copy project: System-Created Entry should only be cleared when Copy Quantity is enabled
+        Initialize();
+
+        // [GIVEN] Create Job with Customer
+        CreateJobWithCustomer(Job);
+
+        // [GIVEN] Create Job Task
+        LibraryJob.CreateJobTask(Job, JobTask);
+
+        // [GIVEN] Create Job Journal Line of type "Both Budget and Billable" and post it.
+        CreateAndPostJobJournalLineWithIteAndType(JobJournalLine, JobTask, JobLineType::"Both Budget and Billable");
+
+        // [GIVEN] Create target Job Id
+        TargetJobNo := LibraryUtility.GenerateGUID();
+
+        // [WHEN] Copy Job by setting Copy Quantity as false.
+        CopyJob.SetCopyOptions(false, false, false, 0, 0, 0);
+        CopyJob.CopyJob(Job, TargetJobNo, TargetJobNo, Job."Bill-to Customer No.", '');
+
+        // [THEN] Find the created Job Planning Line and "System-Created Entry" should remain true when Copy Quantity is disabled
+        JobPlanningLine.SetRange("Job No.", TargetJobNo);
+        JobPlanningLine.FindFirst();
+        Assert.IsTrue(JobPlanningLine."System-Created Entry", ValueNotTrueErr);
     end;

     local procedure Initialize()
@@ -5676,6 +5715,20 @@
         until JobPlanningLine.Next() = 0;
     end;

+    local procedure CreateAndPostJobJournalLineWithIteAndType(var JobJournalLine: Record "Job Journal Line"; JobTask: Record "Job Task"; JobLineType: Enum "Job Line Type")
+    var
+        Item: Record Item;
+    begin
+        LibraryInventory.CreateItem(Item);
+        LibraryJob.CreateJobJournalLine(JobLineType, JobTask, JobJournalLine);
+        JobJournalLine.Validate(Type, JobJournalLine.Type::Item);
+        JobJournalLine.Validate("No.", Item."No.");
+        JobJournalLine.Validate(Quantity, LibraryRandom.RandInt(100));
+        JobJournalLine.Modify(true);
+
+        LibraryJob.PostJobJournal(JobJournalLine);
+    end;
+
     [RequestPageHandler]
     [Scope('OnPrem')]
     procedure TransferSalesCreditMemoReportWithDatesHandler(var JobTransferToCreditMemo: TestRequestPage "Job Transfer to Credit Memo")

